mapper.update:
update cotdl.tbl_piiorderstep
   set 
		status= (select rtrim(case when ok = 0 then 'Ended OK'
					                    when notok > 0 then 'Ended not OK'
					                    when running > 0 then 'Running'
					                    when wait > 0 then 'Running'
					               end)
				   from (
						select 
							  COALESCE(sum(case when status != 'Ended OK' then 1 end),0) as ok
							, COALESCE(sum(case when status = 'Ended not OK' then 1 end),0) as notok 
							, COALESCE(sum(case when status = 'Running' then 1 end),0) as running 
							, COALESCE(sum(case when status = 'Wait condition' then 1 end),0) as wait 
						from cotdl.tbl_piiordersteptable
						where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR}
						)
 				),
		runningtime= (
			       TRUNC((sysdate-realstarttime)*24) || ':' || 
			       LPAD(TRUNC(mod((sysdate - realstarttime)*24,1)*60),2,'0' ) || ':' || 
			       LPAD(TRUNC(round(mod((sysdate - realstarttime)*24*60,1)*60)),2,'0' )
			       
				),
		realendtime= SYSDATE,
		successtabcnt = (select sum(CASE WHEN status='Ended OK' THEN 1 ELSE 0 END)
		  				   from cotdl.tbl_piiordersteptable
		 				  where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR}
 						)
where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR}

update cotdl.tbl_piiorderstep
   set 
		confirmflag= #{confirmflag, jdbcType=VARCHAR},
		holdflag= #{holdflag, jdbcType=VARCHAR},
		forceokflag= #{forceokflag, jdbcType=VARCHAR}
		
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR}

mapper.select:
 
		 
		select 
			orderid, status, confirmflag, holdflag, forceokflag, killflag, basedate, threadcnt, commitcnt, runcnt, jobid, version, stepid, stepname, steptype, stepseq, db, totaltabcnt, successtabcnt, runningtime, realstarttime, realendtime, orderuserid
		from ( 
				select 
					 ROWNUM rn, orderid, status, confirmflag, holdflag, forceokflag, killflag, basedate, threadcnt, commitcnt, runcnt, jobid, version, stepid, stepname, steptype, stepseq, db, totaltabcnt, successtabcnt, runningtime, realstarttime, realendtime, orderuserid
				from (
						select orderid, status, confirmflag, holdflag, forceokflag, killflag, to_char(basedate,'yyyy/mm/dd') as basedate, threadcnt, commitcnt, runcnt, jobid, version, stepid, stepname, steptype, stepseq, db, totaltabcnt, successtabcnt, runningtime, to_char(realstarttime,'yyyy/mm/dd hh24:mi:ss') as realstarttime, to_char(realendtime,'yyyy/mm/dd hh24:mi:ss') as realendtime, orderuserid
					  	  from cotdl.tbl_piiorderstep  
					  	  order by orderid, jobid, version, stepseq
					 ) f
				 
		
	    
		
						
							and upper(jobid) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and basedate = #{search2}
						
						
							and stepid = #{search3}
						
						
							and status = #{search4}
						
		
	    
	    
				
				order by orderid, jobid, version, stepseq
			  ) d
		where rn <= #{pagenum} * #{amount} 
		  and rn > (#{pagenum} -1) * #{amount} 
		order by orderid, jobid, version, stepseq
